SELECT p.platform, p.product_id AS "productId", p.product_name AS "productName", p.brand_name AS "brandName", p.avg_rating AS "avgRating", p.review_count AS "reviewCount", p.n_positive AS "nPositive", a.aspect, SUM(CASE WHEN a.sentiment = 'positive' THEN a.cnt ELSE 0 END) AS "posCnt", SUM(a.cnt) AS "totalCnt" FROM t_product p JOIN t_aspect_sentiment a ON a.platform = p.platform AND a.product_id = p.product_id WHERE p.category = #{category} AND a.aspect IN
#{asp}
AND p.review_count >= 10 GROUP BY p.platform, p.product_id, p.product_name, p.brand_name, p.avg_rating, p.review_count, p.n_positive, a.aspect
